import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Promoter, Enrollment } from '@app/shared/models';
import { EnrollmentService } from '../services/enrollment.service';
import { PromoterService } from '../../promoters/services/promoter.service';

@Component({
  selector: 'app-enrollment-form',
  templateUrl: './enrollment-form.component.html',
  styleUrls: ['./enrollment-form.component.css']
})
export class EnrollmentFormComponent implements OnInit {
  enrollmentForm: FormGroup;
  promoters: Promoter[] = [];
  loading = false;
  submitted = false;
  successMessage: string | null = null;
  errorMessage: string | null = null;

  readonly SEDES = [
    { value: 'SED-001', label: 'SED-001' },
    { value: 'SED-002', label: 'SED-002' },
    { value: 'SED-003', label: 'SED-003' }
  ];

  readonly PROGRAMAS = [
    { value: 'Programa 1', label: 'Programa 1' },
    { value: 'Programa 2', label: 'Programa 2' }
  ];

  readonly MODALIDADES = [
    { value: 'Virtual', label: 'Virtual' },
    { value: 'Presencial', label: 'Presencial' }
  ];

  constructor(
    private fb: FormBuilder,
    private enrollmentService: EnrollmentService,
    private promoterService: PromoterService
  ) {
    this.enrollmentForm = this.fb.group({
      nombre: ['', Validators.required],
      apellido: ['', Validators.required],
      dni: ['', Validators.required],
      sede: ['', Validators.required],
      promotor: ['', Validators.required],
      programa: ['', Validators.required],
      modalidad: ['', Validators.required],
      correo: ['', [Validators.required, Validators.email]]
    });
  }

  ngOnInit(): void {
    this.loadPromoters();
  }

  loadPromoters(): void {
    this.promoterService.getPromoters().subscribe({
      next: (data) => {
        this.promoters = data;
      },
      error: (err) => {
        console.error('Error cargando promotores', err);
      }
    });
  }

  onSubmit(): void {
    this.submitted = true;
    this.successMessage = null;
    this.errorMessage = null;

    if (this.enrollmentForm.invalid) {
      this.errorMessage = 'Por favor completa todos los campos correctamente';
      return;
    }

    this.loading = true;
    const enrollment: Enrollment = this.enrollmentForm.value;

    this.enrollmentService.createEnrollment(enrollment).subscribe({
      next: (response) => {
        this.successMessage = 'Matrícula registrada exitosamente';
        this.enrollmentForm.reset();
        this.submitted = false;
        this.loading = false;
      },
      error: (err) => {
        this.errorMessage = 'Error al registrar la matrícula';
        this.loading = false;
        console.error(err);
      }
    });
  }

  resetForm(): void {
    this.enrollmentForm.reset();
    this.submitted = false;
    this.successMessage = null;
    this.errorMessage = null;
  }
}
<div class="enrollment-form-wrapper">
  <div *ngIf="successMessage" class="success-message">
    {{ successMessage }}
  </div>
  <div *ngIf="errorMessage" class="error-message">
    {{ errorMessage }}
  </div>

  <form [formGroup]="enrollmentForm" (ngSubmit)="onSubmit()" class="enrollment-form">
    <div class="row">
      <div class="field-group">
        <label for="nombre">Nombre</label>
        <input 
          id="nombre" 
          formControlName="nombre" 
          placeholder="Ej. Juan" 
          required 
        />
        <small *ngIf="enrollmentForm.get('nombre')?.invalid && submitted" class="error">
          Campo requerido
        </small>
      </div>
      <div class="field-group">
        <label for="dni">DNI</label>
        <input 
          id="dni" 
          formControlName="dni" 
          placeholder="Ingresa tu número de DNI" 
          required 
        />
        <small *ngIf="enrollmentForm.get('dni')?.invalid && submitted" class="error">
          Campo requerido
        </small>
      </div>
    </div>

    <div class="row">
      <div class="field-group">
        <label for="apellido">Apellido</label>
        <input 
          id="apellido" 
          formControlName="apellido" 
          placeholder="Ej. Perez" 
          required 
        />
        <small *ngIf="enrollmentForm.get('apellido')?.invalid && submitted" class="error">
          Campo requerido
        </small>
      </div>
      <div class="field-group">
        <label for="sede">Sede</label>
        <select id="sede" formControlName="sede" required>
          <option value="">Selecciona una sede</option>
          <option *ngFor="let sede of SEDES" [value]="sede.value">
            {{ sede.label }}
          </option>
        </select>
        <small *ngIf="enrollmentForm.get('sede')?.invalid && submitted" class="error">
          Campo requerido
        </small>
      </div>
    </div>

    <div class="row">
      <div class="field-group">
        <label for="promotor">Promotor</label>
        <select id="promotor" formControlName="promotor" required>
          <option value="">Selecciona un promotor</option>
          <option *ngFor="let promoter of promoters" [value]="promoter.nombreCompleto">
            {{ promoter.nombreCompleto }} ({{ promoter.sede }})
          </option>
        </select>
        <small *ngIf="enrollmentForm.get('promotor')?.invalid && submitted" class="error">
          Campo requerido
        </small>
      </div>
      <div class="field-group">
        <label for="programa">Programa</label>
        <select id="programa" formControlName="programa" required>
          <option value="">Selecciona un programa</option>
          <option *ngFor="let programa of PROGRAMAS" [value]="programa.value">
            {{ programa.label }}
          </option>
        </select>
        <small *ngIf="enrollmentForm.get('programa')?.invalid && submitted" class="error">
          Campo requerido
        </small>
      </div>
    </div>

    <div class="row">
      <div class="field-group">
        <label for="modalidad">Modalidad</label>
        <select id="modalidad" formControlName="modalidad" required>
          <option value="">Selecciona una modalidad</option>
          <option *ngFor="let modalidad of MODALIDADES" [value]="modalidad.value">
            {{ modalidad.label }}
          </option>
        </select>
        <small *ngIf="enrollmentForm.get('modalidad')?.invalid && submitted" class="error">
          Campo requerido
        </small>
      </div>
      <div class="field-group">
        <label for="correo">Correo Electrónico</label>
        <input 
          id="correo" 
          type="email"
          formControlName="correo" 
          placeholder="ejemplo@correo.com" 
          required 
        />
        <small *ngIf="enrollmentForm.get('correo')?.invalid && submitted" class="error">
          Correo válido requerido
        </small>
      </div>
    </div>

    <div class="form-actions">
      <button type="submit" class="btn primary" [disabled]="loading">
        {{ loading ? 'Registrando...' : 'Registrar Matrícula' }}
      </button>
      <button type="button" class="btn secondary" (click)="resetForm()" [disabled]="loading">
        Cancelar
      </button>
    </div>
  </form>
</div>
